160: // GetServicesToUpdateOnPodChange returns a set of Service keys for Services
161: // that have potentially been affected by a change to this pod.
162: func GetServicesToUpdateOnPodChange(serviceLister v1listers.ServiceLister, old, cur interface{}) sets.String {
163: 	newPod := cur.(*v1.Pod)
164: 	oldPod := old.(*v1.Pod)
165: 	if newPod.ResourceVersion == oldPod.ResourceVersion {
166: 		// Periodic resync will send update events for all known pods.
167: 		// Two different versions of the same pod will always have different RVs
168: 		return sets.String{}
169: 	}
170: 
171: 	podChanged, labelsChanged := podEndpointsChanged(oldPod, newPod)
172: 
173: 	// If both the pod and labels are unchanged, no update is needed
174: 	if !podChanged && !labelsChanged {
175: 		return sets.String{}
176: 	}
177: 
178: 	services, err := GetPodServiceMemberships(serviceLister, newPod)
179: 	if err != nil {
180: 		utilruntime.HandleError(fmt.Errorf("unable to get pod %s/%s's service memberships: %v", newPod.Namespace, newPod.Name, err))
181: 		return sets.String{}
182: 	}
183: 
184: 	if labelsChanged {
185: 		oldServices, err := GetPodServiceMemberships(serviceLister, oldPod)
186: 		if err != nil {
187: 			utilruntime.HandleError(fmt.Errorf("unable to get pod %s/%s's service memberships: %v", oldPod.Namespace, oldPod.Name, err))
188: 		}
189: 		services = determineNeededServiceUpdates(oldServices, services, podChanged)
190: 	}
191: 
192: 	return services
193: }
