195: // GetPodFromDeleteAction returns a pointer to a pod if one can be derived from
196: // obj (could be a *v1.Pod, or a DeletionFinalStateUnknown marker item).
197: func GetPodFromDeleteAction(obj interface{}) *v1.Pod {
198: 	if pod, ok := obj.(*v1.Pod); ok {
199: 		// Enqueue all the services that the pod used to be a member of.
200: 		// This is the same thing we do when we add a pod.
201: 		return pod
202: 	}
203: 	// If we reached here it means the pod was deleted but its final state is unrecorded.
204: 	tombstone, ok := obj.(cache.DeletedFinalStateUnknown)
205: 	if !ok {
206: 		utilruntime.HandleError(fmt.Errorf("couldn't get object from tombstone %#v", obj))
207: 		return nil
208: 	}
209: 	pod, ok := tombstone.Obj.(*v1.Pod)
210: 	if !ok {
211: 		utilruntime.HandleError(fmt.Errorf("tombstone contained object that is not a Pod: %#v", obj))
212: 		return nil
213: 	}
214: 	return pod
215: }
