217: func hostNameAndDomainAreEqual(pod1, pod2 *v1.Pod) bool {
218: 	return pod1.Spec.Hostname == pod2.Spec.Hostname &&
219: 		pod1.Spec.Subdomain == pod2.Spec.Subdomain
220: }
