237: func (sl portsInOrder) Len() int      { return len(sl) }
238: func (sl portsInOrder) Swap(i, j int) { sl[i], sl[j] = sl[j], sl[i] }
239: func (sl portsInOrder) Less(i, j int) bool {
240: 	h1 := deepHashObjectToString(sl[i])
241: 	h2 := deepHashObjectToString(sl[j])
242: 	return h1 < h2
