245: // EndpointsEqualBeyondHash returns true if endpoints have equal attributes
246: // but excludes equality checks that would have already been covered with
247: // endpoint hashing (see hashEndpoint func for more info) and ignores difference
248: // in ResourceVersion of TargetRef.
249: func EndpointsEqualBeyondHash(ep1, ep2 *discovery.Endpoint) bool {
250: 	if stringPtrChanged(ep1.NodeName, ep2.NodeName) {
251: 		return false
252: 	}
253: 
254: 	if stringPtrChanged(ep1.Zone, ep2.Zone) {
255: 		return false
256: 	}
257: 
258: 	if boolPtrChanged(ep1.Conditions.Ready, ep2.Conditions.Ready) {
259: 		return false
260: 	}
261: 
262: 	if boolPtrChanged(ep1.Conditions.Serving, ep2.Conditions.Serving) {
263: 		return false
264: 	}
265: 
266: 	if boolPtrChanged(ep1.Conditions.Terminating, ep2.Conditions.Terminating) {
267: 		return false
268: 	}
269: 
270: 	if !semanticIgnoreResourceVersion.DeepEqual(ep1.TargetRef, ep2.TargetRef) {
271: 		return false
272: 	}
273: 
274: 	return true
275: }
