299: // DeepHashObject writes specified object to hash using the spew library
300: // which follows pointers and prints actual values of the nested objects
301: // ensuring the hash does not change when a pointer changes.
302: // copied from k8s.io/kubernetes/pkg/util/hash
303: func deepHashObject(hasher hash.Hash, objectToWrite interface{}) {
304: 	hasher.Reset()
305: 	printer := spew.ConfigState{
306: 		Indent:         " ",
307: 		SortKeys:       true,
308: 		DisableMethods: true,
309: 		SpewKeys:       true,
310: 	}
311: 	printer.Fprintf(hasher, "%#v", objectToWrite)
312: }
